import React, { Component } from 'react';
import MyNominations from './Components/Nominations/MyNominations';
import Search from './Components/Search/Search'
import './App.css';

class App extends Component {
	constructor(props) {
    super(props);
    
    this.state = {
      nominees: []
    };
  }

  nominate = (movie) => {
    if (this.state.nominees.length < 5) {
      this.setState({
        nominees: this.state.nominees.concat([movie])
      });
    }
  }

  removeNomination = (movie) => {
    this.setState({
      nominees: this.state.nominees.filter(
        nom => nom.imdbID !== movie.imdbID
      )
    });
  }

  render() {
    return (
      <div className="App">
        <header className="App-header">
          <p className="title-the"> The </p>
          <p className="title-annual"> 1st Annual </p>
          <p className="title-shoppies"> Shoppies </p>
        </header>
        <MyNominations nominees={this.state.nominees} removeNominee={this.removeNomination}/>
        <Search nominees={this.state.nominees} nominate={this.nominate}/>
      </div>
    );
  }
}

export default App;
